:root {
  --bg-ticket: #1a1a2e;
  --bg-right: #16213e;
  --accent: #e94560;
  --gold: #f5a623;
  --text-primary: #ffffff;
  --text-muted: #8892b0;
  --divider: #8892b0;
  --notch-bg: #f5f5f5;
  --label-size: 10px;
  --radius: 16px;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
}

.ticket {
  display: flex;
  flex-direction: row;
  width: 480px;
  height: 200px;
  background-color: var(--bg-ticket);
  border-radius: var(--radius);
  overflow: visible;
  position: relative;
}

.ticket-left {
  flex: 1;
  padding: 24px 20px 20px 24px;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.event-label {
  font-size: var(--label-size);
  font-weight: 700;
  letter-spacing: 2px;
  color: var(--accent);
}

.event-name {
  font-size: 26px;
  font-weight: 800;
  color: var(--text-primary);
  line-height: 1.1;
  margin-top: 4px;
}

.event-sub {
  font-size: 11px;
  color: var(--text-muted);
  margin-top: 4px;
}

.ticket-details {
  display: flex;
  flex-direction: row;
  gap: 20px;
  margin-top: auto;
}

.detail {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.detail-label {
  font-size: var(--label-size);
  font-weight: 700;
  letter-spacing: 1px;
  color: var(--text-muted);
}

.detail-value {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-primary);
}

.ticket-divider {
  width: 20px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-between;
  position: relative;
  flex-shrink: 0;
}

.notch {
  width: 20px;
  height: 20px;
  background-color: var(--notch-bg);
  border-radius: 50%;
  flex-shrink: 0;
  position: relative;
  z-index: 2;
}

.dash-line {
  flex: 1;
  width: 2px;
  border-left: 2px dashed var(--divider);
  opacity: 0.4;
}

.ticket-right {
  width: 110px;
  background-color: var(--bg-right);
  border-radius: 0 var(--radius) var(--radius) 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 4px;
  flex-shrink: 0;
}

.seat-label {
  font-size: var(--label-size);
  font-weight: 700;
  letter-spacing: 2px;
  color: var(--text-muted);
}

.seat-number {
  font-size: 36px;
  font-weight: 800;
  color: var(--text-primary);
  line-height: 1;
}

.seat-row {
  font-size: var(--label-size);
  font-weight: 600;
  color: var(--text-muted);
  letter-spacing: 1px;
}

.price-tag {
  font-size: 18px;
  font-weight: 700;
  color: var(--gold);
  margin-top: 8px;
}

.ticket-type {
  font-size: var(--label-size);
  font-weight: 700;
  letter-spacing: 3px;
  color: var(--accent);
}
